class Solution:
    def minArrivalsToDiscard(self, arrivals, w, m):
        # brute: recompute the kept-window count from scratch each day
        kept = []  # list of (day, type) kept so far
        discards = 0
        for i, t in enumerate(arrivals):
            day = i + 1
            lo = max(1, day - w + 1)
            cnt = 0
            for (d, tt) in kept:
                if lo <= d <= day and tt == t:
                    cnt += 1
            if cnt + 1 > m:
                discards += 1
            else:
                kept.append((day, t))
        return discards

