class Solution:
    def minArrivalsToDiscard(self, arrivals, w, m):
        from collections import deque, defaultdict
        counts = defaultdict(int)
        kept = deque()  # (day, type) of kept arrivals
        discards = 0
        for i, t in enumerate(arrivals):
            day = i + 1
            lo = day - w + 1
            while kept and kept[0][0] < lo:
                d, tt = kept.popleft()
                counts[tt] -= 1
            if counts[t] + 1 > m:
                discards += 1
            else:
                counts[t] += 1
                kept.append((day, t))
        return discards

