var minArrivalsToDiscard = function(arrivals, w, m) {
    const counts = new Map();
    const keptDay = [];
    const keptType = [];
    let head = 0;
    let discards = 0;
    for (let i = 0; i < arrivals.length; i++) {
        const t = arrivals[i];
        const day = i + 1;
        const lo = day - w + 1;
        while (head < keptDay.length && keptDay[head] < lo) {
            const tt = keptType[head];
            counts.set(tt, counts.get(tt) - 1);
            head++;
        }
        if ((counts.get(t) || 0) + 1 > m) {
            discards++;
        } else {
            counts.set(t, (counts.get(t) || 0) + 1);
            keptDay.push(day);
            keptType.push(t);
        }
    }
    return discards;
};
